  ('elementary-10ced7e2-moex-00621', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '某甲是一名公務人員，某天上班時於等電梯的空檔滑手機，順手在特定候選人的Facebook貼文中按讚。 請問某甲的按讚行為可能觸犯何種法令？', '["可能觸犯公務人員行政中立法", "只是按讚而已，沒有表達實質意見，沒有觸法疑慮", "可能觸犯公務員廉政倫理規範", "可能觸犯行政程序法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00622', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '依據公務員懲戒法，對公務員懲戒之內容與效力，下列敘述何者正確？', '["「申誡」可口頭為之，但「記過」則必須書面通知", "所謂「撤職」係指撤除現職外，並且不得再任用為公務員", "「休職」係指休受懲戒人之職，停發俸（薪）給，且受懲戒人不得申請退休或退伍", "「降級」係指降一級官等，並且不得再任主管職"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00623', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '依公務人員請假規則規定，公務人員休假得以時計，每年至少應休假之日數由下列何者定之？', '["銓敘部", "行政院人事行政總處", "總統府、國家安全會議及五院", "考試院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00624', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '有關公務人員保障事件復審之相關規定，下列敘述何者錯誤？', '["對於服務機關所為之管理措施認為不當，致影響其權益者，均應提起復審", "非現職公務人員基於其原公務人員身分之請求權遭受侵害時，得提起復審", "公務人員之遺族基於該公務人員身分所生之公法上財產請求權遭受侵害時，得提起復審", "俸級審定疑義，得提起復審"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00625', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '我國於民國84年7月1日之後實施公務人員退撫新制，當中退撫基金由政府與公務人員每月各自提撥， 其比率分別為何？', '["政府撥繳55%、公務人員繳付45%", "政府撥繳60%、公務人員繳付40%", "政府撥繳65%、公務人員繳付35%", "政府撥繳70%、公務人員繳付30%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00626', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '某乙年滿55歲，年資14年，已任本職務最高職等年功俸最高級滿三年，自認陞遷無望，萌生去意，今 因單位業務緊縮，乃配合其服務機關依法令辦理精簡，申請自願退休，下列敘述何者正確？', '["某乙僅年滿55歲，且非屬危勞職務，尚不得申請自願退休", "某乙得申請自願退休，但只能支領一次退休金", "某乙得立即支領月退休金，但須為減額月退休金", "某乙得至年滿65歲起，支領月退休金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00627', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '中華民國全國公務人員協會可推派代表參與那一個委員會？', '["公教人員保險監理委員會", "公務人員保障暨培訓委員會", "中央選舉委員會", "公共工程委員會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00628', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '有關公教人員保險，下列敘述何者錯誤？', '["保險費率為被保險人每月保險俸（薪）額7%至15%", "被保險人自付35%的保險費", "私立學校教職員由政府及學校各補助32.5%的保險費", "教育部統一編列預算，核撥政府補助私立學校教職員之保險費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00629', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '下列有關公務人員協會之敘述，何者正確？', '["公務人員協會理事、監事之任期均為二年", "理監事不得連選連任", "理事長沒有連任限制", "該協會為行政機關"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "b918ade7bf01", "answer_pdf_sha1": "90a1ca391de2", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
